(function(){
  const catalog=window.GOALOS_NAV_CATALOG;
  const forbiddenNotice='Browser-local navigation only. No accounts, no forms, no cookies, no analytics, no wallet, no user data wanted.';
  function el(tag,attrs={},html=''){const n=document.createElement(tag);for(const [k,v] of Object.entries(attrs)){if(k==='class')n.className=v;else if(k==='href')n.setAttribute('href',v);else if(k==='type')n.type=v;else if(k==='aria')n.setAttribute('aria-label',v);else n.setAttribute(k,v);}if(html)n.innerHTML=html;return n;}
  function card(p){return `<a class="gnav-card" href="${p.href}"><div class="gnav-meta"><span class="gnav-chip">${p.section}</span><span class="gnav-chip">${p.time}</span></div><h4>${p.title}</h4><p>${p.summary}</p></a>`;}
  function mountOverlay(){
    if(document.querySelector('.gnav-launch')) return;
    const launch=el('button',{class:'gnav-launch',type:'button',aria:'Open GoalOS site navigation'},'Navigate');
    const shell=el('div',{class:'gnav-shell'});
    shell.innerHTML=`<div class="gnav-backdrop"></div><section class="gnav-panel" role="dialog" aria-label="GoalOS navigation"><div class="gnav-head"><div><div class="gnav-kicker">GoalOS Command Center</div><h2 class="gnav-title">Find the right proof path.</h2><p style="color:var(--nav-muted);margin:6px 0 0">${forbiddenNotice}</p></div><button class="gnav-close" type="button">Close</button></div><div class="gnav-body"><aside><input class="gnav-search" aria-label="Filter pages" placeholder="Search pages, demos, proof, legal…"><div class="gnav-filters"></div><div class="gnav-paths"></div></aside><main><div class="gnav-results"></div></main></div></section>`;
    document.body.appendChild(launch); document.body.appendChild(shell);
    const results=shell.querySelector('.gnav-results'), search=shell.querySelector('.gnav-search'), filters=shell.querySelector('.gnav-filters'), paths=shell.querySelector('.gnav-paths');
    let active='all';
    const filterLabels=['all',...catalog.sections.map(s=>s.id)];
    filters.innerHTML=filterLabels.map(x=>`<button class="gnav-filter${x==='all'?' active':''}" type="button" data-filter="${x}">${x==='all'?'All':catalog.sections.find(s=>s.id===x).label}</button>`).join('');
    paths.innerHTML=catalog.paths.map(p=>`<a class="gnav-path" href="${p.steps[0]||p.href}"><span class="gnav-chip">${p.time}</span><strong>${p.title}</strong><span style="color:var(--nav-muted);font-size:13px">${p.steps.length} stops</span></a>`).join('');
    function render(){const q=(search.value||'').toLowerCase().trim();let arr=catalog.pages.filter(p=>(active==='all'||p.section===active)&&(!q||[p.title,p.summary,p.section,...p.audience].join(' ').toLowerCase().includes(q)));results.innerHTML=arr.length?arr.map(card).join(''):'<div class="gnav-empty">No matching page. Try “proof”, “settlement”, “legal”, “router”, or “start”.</div>';}
    filters.addEventListener('click',e=>{const b=e.target.closest('[data-filter]'); if(!b) return; active=b.dataset.filter; filters.querySelectorAll('.gnav-filter').forEach(x=>x.classList.toggle('active',x===b)); render();});
    search.addEventListener('input',render);
    launch.addEventListener('click',()=>{shell.classList.add('open'); render(); setTimeout(()=>search.focus(),40);});
    shell.querySelector('.gnav-close').addEventListener('click',()=>shell.classList.remove('open'));
    shell.querySelector('.gnav-backdrop').addEventListener('click',()=>shell.classList.remove('open'));
    document.addEventListener('keydown',e=>{if(e.key==='Escape') shell.classList.remove('open'); if((e.metaKey||e.ctrlKey)&&e.key.toLowerCase()==='k'){e.preventDefault();shell.classList.add('open');render();search.focus();}});
    render();
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',mountOverlay); else mountOverlay();
})();
